import{_ as r,o as a,c as d,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"ASMR Cards Design — asmr.one 作品改编","description":"","frontmatter":{},"headers":[],"relativePath":"plans/2026-03-16-asmr-cards-design.md","filePath":"plans/2026-03-16-asmr-cards-design.md","lastUpdated":null}'),e={name:"plans/2026-03-16-asmr-cards-design.md"};function l(o,t,s,n,h,p){return a(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="asmr-cards-design-—-asmr-one-作品改编" tabindex="-1">ASMR Cards Design — asmr.one 作品改编 <a class="header-anchor" href="#asmr-cards-design-—-asmr-one-作品改编" aria-label="Permalink to &quot;ASMR Cards Design — asmr.one 作品改编&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>从 asmr.one（DLsite 音声作品库）选取 4 部高人气作品，生成适配 Yumina 的 WorldDefinition v13 卡片。2 SFW + 2 NSFW，各有定制 messageRenderer。</p><h2 id="数据源" tabindex="-1">数据源 <a class="header-anchor" href="#数据源" aria-label="Permalink to &quot;数据源&quot;">​</a></h2><p>asmr.one REST API:</p><ul><li>作品详情: <code>https://api.asmr.one/api/work/{id}</code></li><li>文件列表: <code>https://api.asmr.one/api/tracks/{id}</code></li><li>封面图: <code>https://api.asmr.one/api/cover/{id}.jpg?type=main</code></li><li>DLsite 页面: <code>https://www.dlsite.com/maniax/work/=/product_id/RJ{id}.html</code></li></ul><h2 id="选定作品" tabindex="-1">选定作品 <a class="header-anchor" href="#选定作品" aria-label="Permalink to &quot;选定作品&quot;">​</a></h2><h3 id="sfw-1-rj243448-—-青梅竹马的心跳押入之夜-in-修学旅行" tabindex="-1">SFW-1: RJ243448 — 青梅竹马的心跳押入之夜 in 修学旅行 <a class="header-anchor" href="#sfw-1-rj243448-—-青梅竹马的心跳押入之夜-in-修学旅行" aria-label="Permalink to &quot;SFW-1: RJ243448 — 青梅竹马的心跳押入之夜 in 修学旅行&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>下载量</td><td>374,085</td></tr><tr><td>评分</td><td>4.51 (216 reviews)</td></tr><tr><td>CV</td><td>加藤英美里</td></tr><tr><td>时长</td><td>33分钟 (3 tracks)</td></tr><tr><td>卡级别</td><td>rich-char</td></tr></tbody></table><p><strong>剧情</strong>: 修学旅行旅馆，和青梅竹马意外挤进同一个押入（壁橱），在狭小空间中心跳加速的一夜。</p><p><strong>Track 结构</strong>:</p><ol><li>Happening! — 偶遇</li><li>心跳押入时间 — 壁橱中的亲密时光</li><li>教师室 — 收尾</li></ol><p><strong>角色设计</strong>: 幼馴染少女，活泼但害羞，鼓起勇气的修学旅行之夜</p><ul><li>变量: 心跳度、亲密度、距离感</li><li>规则: 距离感越低 → ASMR 描写越细腻（耳语、呼吸、心跳声）</li><li>messageRenderer: 日式旅馆暖色调，心跳动画，距离指示器</li></ul><h3 id="sfw-2-rj401391-—-梦巫女的治愈-在幽世神社身心俱净" tabindex="-1">SFW-2: RJ401391 — 梦巫女的治愈 ～在幽世神社身心俱净～ <a class="header-anchor" href="#sfw-2-rj401391-—-梦巫女的治愈-在幽世神社身心俱净" aria-label="Permalink to &quot;SFW-2: RJ401391 — 梦巫女的治愈 ～在幽世神社身心俱净～&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>下载量</td><td>116,417</td></tr><tr><td>评分</td><td>4.64 (11,731 ratings)</td></tr><tr><td>CV</td><td>鬼頭明里</td></tr><tr><td>时长</td><td>34分钟 (6 tracks)</td></tr><tr><td>卡级别</td><td>rich-char + 治愈机制</td></tr><tr><td>价格</td><td>免费</td></tr></tbody></table><p><strong>剧情</strong>: 在梦中听到铃声醒来，发现自己身处异世界的幽幻神社。神秘巫女「咲夜」为你进行身心净化仪式。</p><p><strong>Track 结构（6 阶段治愈仪式）</strong>:</p><ol><li>梦中相遇 (4:25)</li><li>净水清洗 (5:23)</li><li>款待 (4:55)</li><li>仪式准备 (6:52)</li><li>仪式 (7:43)</li><li>膝枕送别 (4:54)</li></ol><p><strong>素材</strong>: 有完整 LRC 字幕文件（12 个 .lrc 文件），含台词内容可参考</p><p><strong>角色设计</strong>: 咲夜，幽世神社的梦巫女，温柔中带戏谑</p><ul><li>变量: 身心净化度、灵力、梦境深度</li><li>规则: 6阶段仪式流程推进，每阶段解锁不同治愈互动</li><li>messageRenderer: 和风神社主题，紫蓝+樱色渐变，灵力粒子效果</li></ul><h3 id="nsfw-1-rj432317-—-超色双子偶像女仆的后宫奉仕♪" tabindex="-1">NSFW-1: RJ432317 — 超色双子偶像女仆的后宫奉仕♪ <a class="header-anchor" href="#nsfw-1-rj432317-—-超色双子偶像女仆的后宫奉仕♪" aria-label="Permalink to &quot;NSFW-1: RJ432317 — 超色双子偶像女仆的后宫奉仕♪&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>下载量</td><td>139,390</td></tr><tr><td>评分</td><td>4.78 (22,904 ratings)</td></tr><tr><td>CV</td><td>涼花みなせ, 陽向葵ゅか</td></tr><tr><td>时长</td><td>155分钟 (6 tracks)</td></tr><tr><td>卡级别</td><td>scenario</td></tr><tr><td>排名</td><td>全站日/周/月榜 #1</td></tr></tbody></table><p><strong>剧情</strong>: 两位偶像女仆（ふわり &amp; みや）在屋敷中为主人提供极致奉仕。</p><p><strong>角色</strong>:</p><ul><li><strong>ふわり</strong> (CV: 陽向葵ゅか) — 真诚元气，天然呆，失误后马上恢复</li><li><strong>みや</strong> (CV: 涼花みなせ) — 冷静务实，目标导向，与ふわり形成互补</li></ul><p><strong>Track 结构（6 场景）</strong>:</p><ol><li>新人女仆面试 (25:27)</li><li>禁忌制作人角色扮演 (25:39)</li><li>初体验演出 (26:09)</li><li>事后的现实 (24:51)</li><li>新婚角色扮演 — ふわり solo (25:52)</li><li>认真起来 — みや solo (27:43)</li></ol><p><strong>素材</strong>: 文件中有高画质包装图（JPG 7.6MB + PNG 8.8MB，含无logo版）+ 6个台本脚本 .txt</p><p><strong>设计</strong>:</p><ul><li>变量: ふわり好感度、みや好感度、主人信赖度、后宫和谐度</li><li>规则: 双角色竞争/协作机制，场景解锁</li><li>messageRenderer: 偶像舞台×女仆屋敷，双色系（粉+蓝），角色切换</li></ul><h3 id="nsfw-2-rj285384-—-jk-妈妈的补习班♪" tabindex="-1">NSFW-2: RJ285384 — JK 妈妈的补习班♪ <a class="header-anchor" href="#nsfw-2-rj285384-—-jk-妈妈的补习班♪" aria-label="Permalink to &quot;NSFW-2: RJ285384 — JK 妈妈的补习班♪&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>下载量</td><td>325,154</td></tr><tr><td>评分</td><td>4.52</td></tr><tr><td>CV</td><td>一之瀬りと</td></tr><tr><td>时长</td><td>27分钟 (2 tracks)</td></tr><tr><td>卡级别</td><td>rich-char</td></tr><tr><td>价格</td><td>免费</td></tr></tbody></table><p><strong>剧情</strong>: JK 少女扮演&quot;妈妈&quot;角色，从自我介绍到亲密照顾的温柔体验。</p><p><strong>Track 结构</strong>:</p><ol><li>自我介绍 — 今天开始我就是哥哥的妈妈了</li><li>妈妈也想治愈你的身体</li></ol><p><strong>素材</strong>: 文件中有 2 张包装图（通常版 + 发情版，各 ~1.8MB）</p><p><strong>角色设计</strong>: JK 少女扮演妈妈，照顾欲强，温柔包容但本质青涩</p><ul><li>变量: 安心感、撒娇度、亲密度</li><li>规则: 根据亲密度解锁不同照顾方式</li><li>messageRenderer: 柔和奶油色调 + 校服元素，温暖包裹感</li></ul><h2 id="通用要求" tabindex="-1">通用要求 <a class="header-anchor" href="#通用要求" aria-label="Permalink to &quot;通用要求&quot;">​</a></h2><ol><li><strong>全部中文</strong> — 角色名、变量名、规则名、lorebook entry name、所有用户可见文字</li><li><strong>messageRenderer</strong> — 每张卡定制 TSX 前端，风格各异</li><li><strong>封面图</strong> — 使用 asmr.one 封面 URL 或作品内包装图</li><li><strong>ASMR 特色</strong> — 所有卡的 system prompt 都要强调 ASMR 写作风格：环绕音效描写、耳语距离感、触觉/听觉细节、亲密空间感</li><li><strong>输出目录</strong> — <code>output/</code></li></ol><h2 id="生成顺序" tabindex="-1">生成顺序 <a class="header-anchor" href="#生成顺序" aria-label="Permalink to &quot;生成顺序&quot;">​</a></h2><ol><li>SFW-1 青梅竹马（最受欢迎，作为开局）</li><li>SFW-2 梦巫女（治愈机制较复杂，第二做）</li><li>NSFW-2 JK妈妈（结构简单，先做）</li><li>NSFW-1 双子女仆（scenario 最复杂，最后做）</li></ol>',44)])])}const m=r(e,[["render",l]]);export{g as __pageData,m as default};
